{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以...嗎？' to politely ask for permission or request something. It is equivalent to 'May I...?' or 'Can I...?' in English.",
      "title": "Polite Request with 可以...嗎？",
      "meaning": "Asking for permission or making a polite request",
      "when_to_use": ["When you want to ask for something at a café or shop", "When you need permission to do something"],
      "when_not_to_use": ["When making a direct command or demand", "When speaking to close friends in informal settings"],
      "pragmatic_notes": "In Taiwan, using '可以...嗎？' is very common and polite. It softens the request and shows respect.",
      "word_order_notes": "The structure is: 可以 + verb + object + 嗎？. The verb comes after 可以.",
      "english_contrast": "English uses 'Can I...?' or 'May I...?' with the verb after the subject. Chinese places 可以 before the verb.",
      "korean_contrast": "Korean uses '~을/를 해도 될까요?' which is similar but the verb is at the end.",
      "negative_examples": [
        {
          "text": "可以嗎？咖啡喝？",
          "error": "Word order is wrong. The verb should come after 可以."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以嗎？咖啡喝？",
          "error": "Incorrect word order. Correct: 可以喝咖啡嗎？"
        }
      ],
      "transformation_drills": ["Change '我要咖啡' to a polite request using 可以...嗎？"],
      "production_drills": ["Ask for a cup of tea politely."],
      "common_error_patterns": ["Placing 嗎 before the verb", "Omitting 嗎 at the end"],
      "repair_feedback": {
        "word_order": "Put 可以 first, then the verb, then the object, and end with 嗎.",
        "politeness": "Using 可以...嗎？ is polite. Avoid using 要 directly.",
        "vocabulary": "Use appropriate verbs like 喝, 吃, 拿."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' to express what you want politely. It is softer than '要' and is commonly used in service encounters.",
      "title": "Expressing Wants with 想要",
      "meaning": "Politely stating what you want",
      "when_to_use": ["When ordering food or drinks", "When expressing a desire in a polite manner"],
      "when_not_to_use": ["When making a direct command", "When you are very familiar with the person"],
      "pragmatic_notes": "In Taiwan, '想要' is more polite than '要' and is often used with '麻煩' or '不好意思'.",
      "word_order_notes": "想要 is followed directly by the object. No particle needed.",
      "english_contrast": "English uses 'I would like...' which is similar in politeness. Chinese uses 想要 + object.",
      "korean_contrast": "Korean uses '~을/를 원하다' or '~고 싶다' but the structure is different.",
      "negative_examples": [
        {
          "text": "想要我咖啡。",
          "error": "Incorrect word order. 想要 should be followed directly by the object."
        }
      ],
      "incorrect_examples": [
        {
          "text": "想要我咖啡。",
          "error": "Correct: 我想要咖啡。"
        }
      ],
      "transformation_drills": ["Change '我要紅茶' to a more polite form using 想要."],
      "production_drills": ["Say you want a latte politely."],
      "common_error_patterns": ["Adding 的 between 想要 and object", "Using 想要 with a verb incorrectly"],
      "repair_feedback": {
        "word_order": "Place 想要 directly before the object.",
        "politeness": "Using 想要 is polite. Add 麻煩 or 不好意思 for extra politeness.",
        "vocabulary": "Use 想要 for objects, not actions."
      }
    },
    {
      "pattern": "不好意思，[request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' as a polite softener before making a request. It shows consideration and is very common in Taiwan.",
      "title": "Polite Softener with 不好意思",
      "meaning": "Excuse me, but... (polite request)",
      "when_to_use": ["When starting a request in a shop or café", "When you need to interrupt or ask for a favor"],
      "when_not_to_use": ["When you are angry or frustrated", "When the situation is very formal"],
      "pragmatic_notes": "In Taiwan, '不好意思' is used more often than '對不起' for minor requests. It conveys a sense of 'sorry to bother you'.",
      "word_order_notes": "Place 不好意思 at the beginning of the sentence, followed by the request.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry to bother you' at the beginning. Chinese uses 不好意思 similarly.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다' but 不好意思 is more casual.",
      "negative_examples": [
        {
          "text": "不好意思嗎？我要咖啡。",
          "error": "Do not add 嗎 after 不好意思. It is not a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思嗎？我要咖啡。",
          "error": "Correct: 不好意思，我要咖啡。"
        }
      ],
      "transformation_drills": ["Add 不好意思 to the beginning of '我要一杯水'."],
      "production_drills": ["Politely ask for a menu using 不好意思."],
      "common_error_patterns": ["Adding 嗎 after 不好意思", "Using 不好意思 at the end of the sentence"],
      "repair_feedback": {
        "word_order": "Put 不好意思 at the start of the request.",
        "politeness": "Using 不好意思 makes the request polite and considerate.",
        "vocabulary": "Use 不好意思 before any request."
      }
    }
  ]
}
